final:
module top_module(
	input obf_D, clk, rst, pst,
	output reg Qsimple, Qasyncrst, Qasyncpst
	);always @(posedge clk)
	Qsimple <= obf_D;

always @(posedge clk, posedge rst)begin
	if (rst == 1'b1)
		Qasyncrst <= 1'b0;
	else
		Qasyncrst <= obf_D;
end

always @(posedge clk, posedge rst, posedge pst)begin
	if (rst == 1'b1)
		Qasyncpst <= 1'b0;
	else if (pst == 1'b1)
		Qasyncpst <= 1'b1;
	else
		Qasyncpst <= obf_D;
end

endmodule
